// global variables
volatile int * pixel_ctrl_ptr = (int *)0xFF203020;
volatile int *timer_status   = (int *)0xFF202000;
volatile int *timer_control  = (int *)0xFF202004;
volatile int *timer_periodl  = (int *)0xFF202008;
volatile int *timer_periodh  = (int *)0xFF20200C;
volatile int *KEY_ptr = (int *)0xFF200050;
int music_index = 0;

volatile int pixel_buffer_start; 
short int Buffer1[240][512];
short int Buffer2[240][512];
int next_pipe_index = 0;
int num_pipes_spawned = 0;

struct PipePair pipes [MAX_PIPES]; 

double jump_strength = 0;
int bird_x = 50;
int bird_y = 100;

int prev_bird_x = 50;
int prev_bird_y = 100;

bool game_over = false;
int score = 0;
const short *score_num[10] = {_0, _1, _2, _3, _4, _5, _6, _7, _8, _9};
short score_bg = SKY_COLOUR;

const short *BG = START_SCREEN;

int fall_wait_interval = 10;
int jump_wait_interval = 10;

// function declarations
void wait_for_vsync();
bool timer_done();
void plot_pixel(int x, int y, short int color);
void clear_screen();
void draw_bird(int x, int y);
void erase_bird(int x, int y);
void detect_collision(int pipe);
void update_score();
void start_state();
void game_state();
void end_state();
void process_audio();
void spawn_pipe();
void draw_pipe();
void play_music();

int main(void)
{
    srand(time(NULL));

    // clear timeout bit
    *timer_status = 0;
    // clear any old edge capture bits 
    *(KEY_ptr + 3) = 0xF;

    // load start value
    *timer_periodl = PIPE_SPAWN_INTERVAL_LOW;
    *timer_periodh = PIPE_SPAWN_INTERVAL_HIGH;


    // set front buffer
    *(pixel_ctrl_ptr + 1) = (int)&Buffer1;
    wait_for_vsync();
    pixel_buffer_start = *pixel_ctrl_ptr;
    clear_screen();

    // set back buffer
    *(pixel_ctrl_ptr + 1) = (int)&Buffer2;
    pixel_buffer_start = *(pixel_ctrl_ptr + 1);
    clear_screen();
    
    while (1){
        start_state();
        game_state();
        end_state();
    }
}

void start_state(){
    BG = START_SCREEN;
    clear_screen();
    wait_for_vsync();
    pixel_buffer_start = *(pixel_ctrl_ptr + 1);
    clear_screen();

    int pressed = *(KEY_ptr + 3);

    while (!(pressed & 0x1)){
        pressed = *(KEY_ptr + 3);
    }

    *(KEY_ptr + 3) = 0x1; 
}

void game_state(){
    //reset vars
    next_pipe_index = 0;
    num_pipes_spawned = 0;
    game_over = false;
    score = 0;
    score_bg = SKY_COLOUR;
    bird_y = 120;
    prev_bird_y = 0;
    bird_velocity = 0;
    jump_strength = 0;
    jump_wait_interval = 10;
    fall_wait_interval = 10;
    
    for (int i = 0 ; i < MAX_PIPES ; i ++){
        pipes[i].bottom_length = 0;
        pipes[i].top_length = 0;
        pipes[i].x = 0;
    }

    BG = GAME_SCREEN;
    clear_screen();
    wait_for_vsync();
    pixel_buffer_start = *(pixel_ctrl_ptr + 1);
    clear_screen();

    spawn_pipe();

    // START = bit 2, CONT = bit 1
    *timer_control = (1 << 2) | (1 << 1);
    *timer_status = 0;

    while(!game_over)
    {
        // update positions
        for(int i = 0; i < num_pipes_spawned; i++){
            pipes[i].x--;
            // if pipe has passed the bird, increment score
            if((pipes[i].x + PIPE_WIDTH) ==  bird_x){
                score++;
            }
        }

        if (timer_done()){
            spawn_pipe();
        }

        //updates jump strength based on audio input

        play_music(); 


        process_audio();

        if (jump_strength > 60){
            if (jump_wait_interval <= 0){
                bird_velocity += JUMP;
                jump_wait_interval = 10;
            }
            else
                jump_wait_interval--;
        }
        else{
            if (fall_wait_interval <= 0){
                bird_velocity += GRAVITY;
                fall_wait_interval = 10;
            }
            else
                fall_wait_interval--;
        }
        bird_y += bird_velocity;
        // bounds (so it doesn't fly off screen)
        if (bird_y < 0) {
            bird_y = 0;
        }
        else if (bird_y > SCREEN_HEIGHT - BIRD_HEIGHT) {
            bird_y = SCREEN_HEIGHT - BIRD_HEIGHT;
        }

        //update game screen
        erase_bird(prev_bird_x, prev_bird_y);
        draw_bird(bird_x, bird_y);
        draw_pipe();
        update_score();

        wait_for_vsync();
        pixel_buffer_start = *(pixel_ctrl_ptr + 1);

        erase_bird(prev_bird_x, prev_bird_y);
        draw_bird(bird_x, bird_y);
        draw_pipe();
        update_score();

        // update previous bird position
        prev_bird_x = bird_x;
        prev_bird_y = bird_y;
    }
}

void end_state(){
    // START = bit 2, CONT = bit 1
    *timer_control = (0 << 2) | (0 << 1);
    *timer_status = 0;

	BG = END_SCREEN;
    clear_screen();
    wait_for_vsync();
    pixel_buffer_start = *(pixel_ctrl_ptr + 1);
    clear_screen();

    int pressed = *(KEY_ptr + 3);

    while (!(pressed & 0x1)){
        pressed = *(KEY_ptr + 3);
    }

    *(KEY_ptr + 3) = 0x1; 
}

bool timer_done() {
    if ((*timer_status) & 1) {
        *timer_status = 0;   // clear TO
        return true;
    }
    return false;
}

void play_music() {
    volatile int * audio_ptr = (int *) AUDIO_BASE;
    int fifospace = *(audio_ptr + 1);

    // check if output FIFO has space
    if ((fifospace & 0x00FF0000) > 0) {

        int16_t sample = bg_music[music_index];

        *(audio_ptr + 2) = sample; // left
        *(audio_ptr + 3) = sample; // right

        music_index++;

        // loop music
        if (music_index >= MUSIC_LENGTH) {
            music_index = 0;
        }
    }
}

void spawn_pipe()
{   
    // pick a random pipe height between PIPE_MIN_HEIGHT and PIPE_MAX_HEIGHT
    int top_pipe_length = (rand() % (PIPE_MAX_HEIGHT - PIPE_MIN_HEIGHT + 1)) + PIPE_MIN_HEIGHT;
    int bottom_pipe_length = SCREEN_HEIGHT - PIPE_SPACE - top_pipe_length;

    pipes[next_pipe_index].x = SCREEN_WIDTH;
    pipes[next_pipe_index].top_length = top_pipe_length;
    pipes[next_pipe_index].bottom_length = bottom_pipe_length;

    if (num_pipes_spawned < MAX_PIPES) {
        num_pipes_spawned++;
    }

    next_pipe_index = (next_pipe_index + 1) % MAX_PIPES;
}   

void draw_pipe(){
    // iterate through all pipes and draw them
    for (int pipe = 0 ; pipe < num_pipes_spawned ; pipe++){
        for(int i = 0; i < pipes[pipe].top_length; i++){
            // erase previous line of pipe
			plot_pixel(pipes[pipe].x + PIPE_WIDTH, i, BG[i * SCREEN_WIDTH + pipes[pipe].x + PIPE_WIDTH - 1]);
            //check overlap with score labels
			if (pipes[pipe].x > (SCREEN_WIDTH - PADDING - 2 * SCORE_WIDTH) && pipes[pipe].x < (SCREEN_WIDTH - PADDING) && i > PADDING && i < (PADDING + SCORE_HEIGHT)){
				score_bg = PIPE_COLOUR;
                continue;
			}
            // draw next line of pipe
            plot_pixel(pipes[pipe].x, i, PIPE_COLOUR);
        }


        for(int i = SCREEN_HEIGHT; i > SCREEN_HEIGHT - pipes[pipe].bottom_length; i--){
            // erase previous line of pipe
			plot_pixel(pipes[pipe].x + PIPE_WIDTH, i, BG[i * SCREEN_WIDTH + pipes[pipe].x + PIPE_WIDTH - 1]);
            // draw next line of pipe
            plot_pixel(pipes[pipe].x, i, PIPE_COLOUR);
        }

        // if pipe is within x range of the bird check for collision
        if (pipes[pipe].x <= (bird_x + BIRD_WIDTH) && (pipes[pipe].x + PIPE_WIDTH) > bird_x){
            detect_collision(pipe);
        }
    }
}

void clear_screen (){
    for (int x = 0 ; x < 320 ; x++){
        for (int y = 0 ; y < 240 ; y++){
            plot_pixel(x, y, BG[SCREEN_WIDTH * y + x]);
        }
    }
}

void plot_pixel(int x, int y, short int color)
{
    if (x < 0 || x > SCREEN_WIDTH || y < 0 || y > SCREEN_HEIGHT)
        return;

    volatile short int *one_pixel_address;

    one_pixel_address = (short int *)(pixel_buffer_start + (y << 10) + (x << 1));
    *one_pixel_address = color;
}

void wait_for_vsync()
{
    volatile int * pixel_ctrl_ptr = (int *)0xFF203020;
    int status;

    *pixel_ctrl_ptr = 1;

    status = *(pixel_ctrl_ptr + 3);
    while((status & 0x01) != 0)
        status = *(pixel_ctrl_ptr + 3);
}

void draw_bird(int x, int y)
{
    for (int row = 0; row < BIRD_HEIGHT; row++) {
        for (int col = 0; col < BIRD_WIDTH; col++) {

            short color = BIRD[row * BIRD_WIDTH + col];

            // skip black pixels (transparent)
            if (color != 0x0000) {
                plot_pixel(x + col, y + row, color);
            }
        }
    }
}

void erase_bird(int x, int y)
{
    for (int row = 0; row < BIRD_HEIGHT; row++) {
        for (int col = 0; col < BIRD_WIDTH; col++) {

            int draw_x = x + col;
            int draw_y = y + row;

            if (draw_x >= 0 && draw_x < SCREEN_WIDTH &&
                draw_y >= 0 && draw_y < SCREEN_HEIGHT) {

                plot_pixel(draw_x, draw_y,
                    BG[draw_y * SCREEN_WIDTH + draw_x]);
            }
        }
    }
}

//audio processing

#define AUDIO_BASE 0xFF203040
void process_audio() {
    jump_strength = 0;
    // Audio codec Register address
    volatile int * audio_ptr = (int *) AUDIO_BASE;
    // intermediate values
    int fifospace;
    // This is an infinite loop checking the RARC to see if there is at least a single
    // entry in the input fifos. If there is, just copy it over to the output fifo.
    // The timing of the input fifo controls the timing of the output
    fifospace = *(audio_ptr + 1); // read the audio port fifospace register
    int count = 0;
    long sum = 0;
    while ((fifospace & 0xFF) > 0 && count < 64) // check RARC to see if there is data to read and average buffer
    {
        // load both input microphone channels - just get one sample from each
        int left = *(audio_ptr + 2);
        int right = *(audio_ptr + 3);

        //find average amplitude for jump strength
        long sample = ((abs(left) + abs(right))/2)/1000000;

        sum += sample;
        count++;

        fifospace = *(audio_ptr + 1); // read the audio port fifospace register
    }

    if (count > 0){
        jump_strength = sum/count;
    }
}

void detect_collision(int pipe){
    //pipe collision check
    if (pipes[pipe].top_length >= bird_y || (SCREEN_HEIGHT - pipes[pipe].bottom_length) <= (bird_y + BIRD_HEIGHT)){
        game_over = true;
        return;
    } 
}

void update_score(){
    int num_1 = score/10;
    int num_0 = score%10;

    for (int i = 0 ; i < SCORE_WIDTH ; i++){
        for (int j = 0 ; j < SCORE_HEIGHT ; j++){

            short colour_0 = abs(score_num[num_0][j * SCORE_WIDTH + i]) == 40669 ? score_bg : score_num[num_0][j * SCORE_WIDTH + i];
            short colour_1 = abs(score_num[num_1][j * SCORE_WIDTH + i]) == 40669 ? score_bg : score_num[num_1][j * SCORE_WIDTH + i];

            plot_pixel(SCREEN_WIDTH - PADDING - 2*SCORE_WIDTH + i, PADDING + j, colour_1);
            plot_pixel(SCREEN_WIDTH - PADDING - SCORE_WIDTH + i, PADDING + j, colour_0);
        }
    }
}
